protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // Preserve EF Core 8 discriminator property name ("Discriminator" instead of "$type")
        // so existing 500K documents and direct SQL queries (c.Discriminator) remain valid.
        entity.HasDiscriminator<string>("Discriminator");

        // Preserve EF Core 8 compound id format ("Product|123" instead of "123")
        // so FindAsync and point-reads continue to locate existing documents.
        entity.HasRootDiscriminatorInJsonId(true);
    });
    // Removed HasIndex — Cosmos DB provider now throws at startup.
    // Manage indexing via the container's indexing policy (Azure Portal / Bicep / Terraform).
}

